import { useNavigate } from "react-router-dom";
import { CartView } from "../components/organisms";
import { useCart } from "../context/CartContext";
import "./Cart.css";

import { Button, Icon } from "../components/atoms";
export default function Cart() {
  const { cartItems, clearCart, getTotalItems, getTotalPrice, posClientName } = useCart();

  const navigate = useNavigate();

  if (cartItems.length === 0) {
    return (
      <div className="cart">
        {posClientName && (
          <div className="cart-client-welcome" style={{ padding: '1rem', backgroundColor: '#f1f5f9', borderRadius: '8px', marginBottom: '1rem', border: '1px solid #cbd5e1' }}>
            <h2 style={{ margin: 0, color: '#334155', fontSize: '1.2rem' }}>Bienvenido {posClientName}</h2>
          </div>
        )}
        <div className="cart-empty">
          <Icon name="cart" size={100}></Icon>
          <h2>Tu carrito está vacío</h2>
          <p>Agrega algunos productos para empezar a comprar</p>
          <Button variant="primary" onClick={() => navigate("/")}>
            <span>Continuar Comprando</span>
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="cart">
      {posClientName && (
        <div className="cart-client-welcome" style={{ padding: '1rem', backgroundColor: '#f1f5f9', borderRadius: '8px', marginBottom: '1rem', border: '1px solid #cbd5e1' }}>
          <h2 style={{ margin: 0, color: '#334155', fontSize: '1.2rem' }}>Bienvenido {posClientName}</h2>
        </div>
      )}
      <div className="cart-header">
        <div className="cart-header-title">
          <Icon name="cart" size={32} />
          <h1>Carrito de Compras</h1>
        </div>
        <div className="cart-header-info">
          <span className="cart-items-count">
            {getTotalItems()} {getTotalItems() === 1 ? "artículo" : "artículos"}
          </span>
          <Button
            variant="ghost"
            className="danger clear-cart-btn"
            onClick={clearCart}
            title="Vaciar carrito"
            size="sm"
          >
            <Icon name="trash" size={18} />
            <span>Vaciar carrito</span>
          </Button>
        </div>
      </div>

      <div className="cart-items">
        <CartView />
        <div className="cart-summary">
          <div className="cart-total">
            <span className="cart-total-subtitle">Total a pagar</span>
            <h2>${getTotalPrice().toFixed(2)}</h2>
          </div>
          <div className="cart-actions">
            <Button
              variant="primary"
              onClick={() => navigate("/checkout")}
              size="lg"
              disabled={!cartItems || cartItems.length === 0}
              title={
                !cartItems || cartItems.length === 0
                  ? "Agrega productos al carrito para continuar"
                  : "Proceder al pago"
              }
            >
              <Icon name="creditCard" size={20} />
              <span>Proceder al pago</span>
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}
